def decode_jwt_unverified(token: str) -> dict:
    """
    Decode a JWT token WITHOUT signature verification.
    FOR DEBUGGING/DEVELOPMENT PURPOSES ONLY.
    
    Returns the header, payload, and metadata about the token.
    """
    if not token or not isinstance(token, str):
        raise ValueError("Token must be a non-empty string")

    # Sanitize: strip whitespace and "Bearer " prefix if present
    token = token.strip()
    if token.lower().startswith("bearer "):
        token = token[7:].strip()

    # Validate token structure (should have 3 parts separated by dots)
    parts = token.split(".")
    if len(parts) != 3:
        raise ValueError(
            f"Invalid JWT structure: expected 3 parts, got {len(parts)}"
        )

    try:
        header = jwt.get_unverified_header(token)
    except jwt.exceptions.DecodeError as e:
        raise ValueError(f"Failed to decode JWT header: {e}")

    try:
        payload = jwt.decode(token, options={
            "verify_signature": False,
            "verify_exp": False,
            "verify_aud": False,
            "verify_iss": False,
            "verify_nbf": False,
            "verify_iat": False,
        })
    except jwt.exceptions.DecodeError as e:
        raise ValueError(f"Failed to decode JWT payload: {e}")

    # Build metadata
    metadata = {}
    now = time.time()

    if "exp" in payload:
        exp = payload["exp"]
        metadata["expires_at"] = time.strftime(
            "%Y-%m-%d %H:%M:%S UTC", time.gmtime(exp)
        )
        metadata["is_expired"] = now > exp
        if metadata["is_expired"]:
            metadata["expired_seconds_ago"] = int(now - exp)
        else:
            metadata["expires_in_seconds"] = int(exp - now)

    if "iat" in payload:
        iat = payload["iat"]
        metadata["issued_at"] = time.strftime(
            "%Y-%m-%d %H:%M:%S UTC", time.gmtime(iat)
        )
        metadata["token_age_seconds"] = int(now - iat)

    if "nbf" in payload:
        nbf = payload["nbf"]
        metadata["not_before"] = time.strftime(
            "%Y-%m-%d %H:%M:%S UTC", time.gmtime(nbf)
        )
        metadata["is_active"] = now >= nbf
    
    return {
        "header": header,
        "payload": payload,
        "metadata": metadata,
    }


def verify_jwt(
    token: str,
    secret: str,
    algorithms: Optional[list] = None,
    audience: Optional[str] = None,
    issuer: Optional[str] = None,
) -> dict:
    """
    Decode and VERIFY a JWT token with signature validation.
    
    Args:
        token: The JWT token string.
        secret: The secret key or public key for verification.
        algorithms: List of allowed algorithms (defaults to ["HS256"]).
                    Explicitly specifying algorithms prevents algorithm confusion attacks.
        audience: Expected audience claim (optional).
        issuer: Expected issuer claim (optional).
    
    Returns:
        Dict with header, payload, metadata, and verification status.
    """
    if not token or not isinstance(token, str):
        raise ValueError("Token must be a non-empty string")
    if not secret or not isinstance(secret, str):
        raise ValueError("Secret must be a non-empty string")

    token = token.strip()
    if token.lower().startswith("bearer "):
        token = token[7:].strip()

    # Default to HS256 only — never allow "none" algorithm
    if algorithms is None:
        algorithms = ["HS256"]

    # Explicitly reject the "none" algorithm to prevent algorithm confusion attacks
    sanitized_algorithms = [
        alg for alg in algorithms if alg.lower() != "none"
    ]
    if not sanitized_algorithms:
        raise ValueError("No valid algorithms specified. 'none' algorithm is not allowed.")

    result = {
        "header": None,
        "payload": None,
        "metadata": {},
        "verified": False,
        "error": None,
    }

    try:
        result["header"] = jwt.get_unverified_header(token)
    except jwt.exceptions.DecodeError as e:
        result["error"] = f"Failed to decode header: {e}"
        return result

    # Check for algorithm mismatch before verification
    token_alg = result["header"].get("alg", "unknown")
    if token_alg.lower() == "none":
        result["error"] = "Token uses 'none' algorithm — rejected for security."
        return result

    decode_options = {}
    decode_kwargs: dict[str, Union[str, list, dict, bool]] = {
        "jwt": token,
        "key": secret,
        "algorithms": sanitized_algorithms,
        "options": decode_options,
    }

    if audience:
        decode_kwargs["audience"] = audience
    if issuer:
        decode_kwargs["issuer"] = issuer

    try:
        payload = jwt.decode(**decode_kwargs)
        result["payload"] = payload
        result["verified"] = True
    except jwt.ExpiredSignatureError:
        result["error"] = "Token has expired"
        # Still decode for inspection
        try:
            result["payload"] = jwt.decode(
                token, secret, algorithms=sanitized_algorithms,
                options={"verify_exp": False}
            )
        except Exception:
            pass
    except jwt.InvalidAudienceError:
        result["error"] = "Invalid audience claim"
    except jwt.InvalidIssuerError:
        result["error"] = "Invalid issuer claim"
    except jwt.InvalidSignatureError:
        result["error"] = "Invalid signature — token may have been tampered with"
    except jwt.InvalidAlgorithmError:
        result["error"] = (
            f"Algorithm mismatch: token uses '{token_alg}', "
            f"allowed: {sanitized_algorithms}"
        )
    except jwt.DecodeError as e:
        result["error"] = f"Failed to decode token: {e}"
    except jwt.InvalidTokenError as e:
        result["error"] = f"Invalid token: {e}"

    # Add metadata if payload was decoded
    if result["payload"]:
        now = time.time()
        payload = result["payload"]
        metadata = result["metadata"]

        if "exp" in payload:
            exp = payload["exp"]
            metadata["expires_at"] = time.strftime(
                "%Y-%m-%d %H:%M:%S UTC", time.gmtime(exp)
            )
            metadata["is_expired"] = now > exp

        if "iat" in payload:
            iat = payload["iat"]
            metadata["issued_at"] = time.strftime(
                "%Y-%m-%d %H:%M:%S UTC", time.gmtime(iat)
            )
            metadata["token_age_seconds"] = int(now - iat)

    return result


def pretty_print_jwt(decoded: dict) -> str:
    """Format decoded JWT info for readable console output."""
    lines = []
    lines.append("=" * 60)
    lines.append("JWT TOKEN INSPECTION")
    lines.append("=" * 60)

    if decoded.get("header"):
        lines.append("\n--- HEADER ---")
        lines.append(json.dumps(decoded["header"], indent=2))

    if decoded.get("payload"):
        lines.append("\n--- PAYLOAD ---")
        # Redact potentially sensitive fields for display
        sensitive_keys = {"password", "secret", "credit_card", "ssn", "pin"}
        display_payload = {}
        for k, v in decoded["payload"].items():
            if k.lower() in sensitive_keys:
                display_payload[k] = "[REDACTED]"
            else:
                display_payload[k] = v
        lines.append(json.dumps(display_payload, indent=2, default=str))

    if decoded.get("metadata"):
        lines.append("\n--- METADATA ---")
        lines.append(json.dumps(decoded["metadata"], indent=2))

    if "verified" in decoded:
        lines.append(f"\n--- VERIFICATION: {'PASSED ✓' if decoded['verified'] else 'FAILED ✗'} ---")
        if decoded.get("error"):
            lines.append(f"Error: {decoded['error']}")

    lines.append("=" * 60)
    return "\n".join(lines)


